class _DeepLinkHandlerState extends State<DeepLinkHandler> {
  String? _initialLink;
  final _linkStream = StreamController<String?>();

  @override
  void initState() {
    super.initState();
    _initUniLinks();
  }

  Future<void> _initUniLinks() async {
    try {
      // Handle initial link
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _handleLink(initialLink);
      }

      // Listen for incoming links
      uriLinkStream.listen((Uri? uri) {
        if (uri != null) {
          _handleLink(uri.toString());
        }
      }, onError: (err) {
        print('Error handling link: $err');
      });
    } catch (e) {
      print('Error initializing uni_links: $e');
    }
  }

  void _handleLink(String link) {
    try {
      final uri = Uri.parse(link);
      
      // Validate scheme
      if (uri.scheme != 'myapp') {
        return;
      }

      // Parse path segments
      final pathSegments = uri.pathSegments;
      if (pathSegments.isEmpty) return;

      // Handle different routes
      switch (pathSegments[0]) {
        case 'profile':
          if (pathSegments.length > 1) {
            final userId = pathSegments[1];
            _navigateToProfile(userId);
          }
          break;
        case 'payment':
          if (pathSegments.length > 1 && pathSegments[1] == 'confirm') {
            _navigateToPaymentConfirmation();
          }
          break;
        default:
          // Handle unknown paths
          break;
      }
    } catch (e) {
      print('Error parsing link: $e');
    }
  }

  void _navigateToProfile(String userId) {
    Navigator.of(context).pushNamed('/profile', arguments: {'userId': userId});
  }

  void _navigateToPaymentConfirmation() {
    Navigator.of(context).pushNamed('/payment/confirm');
  }

